  useFrame((state, delta) => {
    if (groupRef.current && !isPaused) {
      groupRef.current.rotation.y += delta * 0.5 * simulationSpeed;
    }
  });

  return (
    <group ref={groupRef}>
      <mesh 
        ref={meshRef} 
