             const speed = 1.0 + Math.abs(activeDy * zoomSensitivity);
             if (activeDy > 0) {
                 controlsRef.current.dollyOut(speed);
             } else {
                 controlsRef.current.dollyIn(speed);
             }
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);

  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); 

  const [focusTarget, setFocusTarget] = useState<{ id: string, size: number } | null>(null);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);

  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
    const root = document.getElementById('root');
    if (root) root.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
    // 飞回太阳，距离采用 CameraFlyTo 中定义的 140 默认距离
    setFocusTarget({ id: SUN_DATA.id, size: SUN_DATA.size });
  };

  const getPlanetSize = (id: string): number => {
      if (id === 'sun') return SUN_DATA.size;
      if (id === 'moon') return MOON_DATA.size;
      if (id === 'tiangong') return TIANGONG_DATA.size;

      const p = PLANETS.find(x => x.id === id);
      if (p) return p.size;

      const jm = JUPITER_MOONS.find(x => x.id === id);
      if (jm) return jm.size;

      const sm = SATURN_MOONS.find(x => x.id === id);
      if (sm) return sm.size;

      return 1; 
  };

  const handleDoubleClick = (id: string) => {
      const size = getPlanetSize(id);
      setFocusTarget({ id, size });
      handleSelect(id);
  };

  const togglePluto = () => {
    const newValue = !showPluto;
    setShowPluto(newValue);
    if (!newValue && selectedPlanetId === 'pluto') {
      handleClose();
    }
  };

  const toggleOrbits = () => {
    setShowOrbits(!showOrbits);
  };

  const handleGestureControl = (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => {
    gestureVelocity.current = { dx, dy, gestureType };
  };

  const toggleGestureMode = () => {
    const nextState = !isGestureMode;
    setIsGestureMode(nextState);
    if (nextState) {
      setSimulationSpeed(1.0);
    } else {
      setIsARMode(false);
    }
  };

  const handleToggleStarship = () => {
    const activating = !isStarshipActive;
    setIsStarshipActive(activating);
    if (activating) {
       setIsPaused(false);
       setSimulationSpeed(0.5); 
       setFocusTarget(null);
    } else {
       setSimulationSpeed(1.0);
    }
  };

  const handleMissionComplete = () => {
     setIsStarshipActive(false);
     setSimulationSpeed(1.0); 
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;

    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    const jMoon = JUPITER_MOONS.find(m => m.id === selectedPlanetId);
    if (jMoon) return jMoon;
    return SATURN_MOONS.find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  const displayedPlanets = useMemo(() => {
    return showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto');
  }, [showPluto]);

  return (
    <div className="w-full h-screen relative overflow-hidden transition-colors duration-500"
         style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}
    >

      <UIOverlay 
        selectedPlanet={selectedPlanet}
        onClose={handleClose}
        isPaused={isPaused}
        togglePause={() => setIsPaused(!isPaused)}
        simulationSpeed={simulationSpeed}
        setSimulationSpeed={setSimulationSpeed}
        isStarshipActive={isStarshipActive}
        toggleStarship={handleToggleStarship}
        showPluto={showPluto}
        togglePluto={togglePluto}
        isGestureMode={isGestureMode}
        toggleGestureMode={toggleGestureMode}
        showOrbits={showOrbits}
        toggleOrbits={toggleOrbits}
      />

      {isGestureMode && (
        <GestureController 
          onControl={handleGestureControl} 
          onClose={() => toggleGestureMode()} 
          isARMode={isARMode}
          toggleARMode={() => setIsARMode(!isARMode)}
        />
      )}

      <Canvas 
        gl={{ antialias: true, toneMappingExposure: 1.2, alpha: true }}
        onPointerMissed={() => {
          if (selectedPlanetId) {
            handleClose();
          }
        }}
      >
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />

          <OrbitControls 
            ref={controlsRef}
            makeDefault
            enabled={!isStarshipActive} 
            enableDamping={true}
            dampingFactor={0.05}
            enablePan={false}
            minDistance={2}
            maxDistance={500}
            maxPolarAngle={Math.PI / 1.8}
            autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive && !focusTarget}
            autoRotateSpeed={0.1 * simulationSpeed} 
          />

          <CameraFlyTo 
             target={focusTarget} 
             planetRefs={planetRefs} 
             controlsRef={controlsRef} 
             setTarget={setFocusTarget} 
          />

          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />

          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} decay={1} color="#FFF5E0" />
          <ambientLight intensity={0.15} color="#404060" />

          <Stars radius={400} depth={50} count={3000} factor={4} saturation={0.5} fade speed={0.5} />

          {!isARMode && <Skybox />}

          <Sparkles count={400} scale={200} size={6} speed={0.2} opacity={0.4} noise={0.1} color="#88AAFF" />
          <Sparkles count={150} scale={150} size={3} speed={0.3} opacity={0.6} color="#FFD700" />

          <Sun 
             onSelect={handleSelect}
             onDoubleClick={handleDoubleClick}
             isSelected={selectedPlanetId === 'sun'}
             isPaused={isPaused}
             simulationSpeed={simulationSpeed}
             planetRefs={planetRefs}
          />

          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />

          {displayedPlanets.map((planet) => (
            <Planet 
              key={planet.id} 
              data={planet} 
              isSelected={selectedPlanetId === planet.id}
              onSelect={handleSelect}
              onDoubleClick={handleDoubleClick}
              isPaused={isPaused}
              simulationSpeed={simulationSpeed}
              earthPositionRef={earthPositionRef}
              planetRefs={planetRefs}
              isStarshipActive={isStarshipActive}
              showOrbit={showOrbits}
            />
          ))}

          {isStarshipActive && (
             <Starship 
                planetRefs={planetRefs} 
                onMissionComplete={handleMissionComplete}
             />
          )}

        </Suspense>
      </Canvas>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onAction: (x: number, y: number, actionType: 'pinch' | 'peace') => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onAction,
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  const prevHandDistanceRef = useRef<number | null>(null);
  const lastActionTimeRef = useRef<number>(0);
  const isPinchingRef = useRef<boolean>(false);

  const [statusMessage, setStatusMessage] = useState<string>("启动魔法手势...");

  useEffect(() => {
    let isMounted = true;
    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );
        if (!isMounted) return;
        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2
        });
        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) {
          setLoading(false);
          setStatusMessage("初始化失败");
        }
      }
    };
    init();
    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 640 }, height: { ideal: 480 }, facingMode: "user" } 
      });
      if (videoRef.current) videoRef.current.srcObject = stream;
      setLoading(false);
      setStatusMessage("准备好了！");
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
      setStatusMessage("无法打开摄像头");
    }
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current) return;
    if (videoRef.current.readyState < 2) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }
    const result = landmarkerRef.current.detectForVideo(videoRef.current, performance.now());
    processGestures(result);
    if (canvasRef.current) draw(result);
    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;
    if (!hands || hands.length === 0) {
      onControl(0, 0, 'rotate');
      prevHandDistanceRef.current = null;
      isPinchingRef.current = false;
      return;
    }

    const now = Date.now();
    const hand = hands[0];
    const cursor = hand[9];
    const screenX = 1.0 - cursor.x;
    const screenY = cursor.y;

    // --- 1. 检测捏合手势 (Thumb + Index) ---
    // Landmark 4: Thumb Tip, Landmark 8: Index Tip
    const pinchDist = Math.hypot(hand[4].x - hand[8].x, hand[4].y - hand[8].y);
    const PINCH_THRESHOLD = 0.04;

    if (pinchDist < PINCH_THRESHOLD) {
      if (!isPinchingRef.current && (now - lastActionTimeRef.current > 800)) {
        isPinchingRef.current = true;
        lastActionTimeRef.current = now;
        onAction(screenX, screenY, 'pinch');
        setStatusMessage("👌 抓取成功！");
      }
    } else {
      isPinchingRef.current = false;
    }

    // --- 2. 检测比耶手势 (Peace/Victory) ---
    // 食指(8)和中指(12)伸直，无名指(16)和尾指(20)弯曲
    const isIndexExtended = hand[8].y < hand[6].y;
    const isMiddleExtended = hand[12].y < hand[10].y;
    const isRingFolded = hand[16].y > hand[14].y;
    const isPinkyFolded = hand[20].y > hand[18].y;

    if (isIndexExtended && isMiddleExtended && isRingFolded && isPinkyFolded) {
      if (now - lastActionTimeRef.current > 1200) {
        lastActionTimeRef.current = now;
        onAction(screenX, screenY, 'peace');
        setStatusMessage("✌️ 魔法关闭！");
      }
    }

    // --- 3. 基础旋转/缩放控制 ---
    if (hands.length === 2) {
      const h1 = hands[0][9]; 
      const h2 = hands[1][9];
      const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);
      if (prevHandDistanceRef.current !== null) {
        const delta = dist - prevHandDistanceRef.current;
        if (Math.abs(delta) > 0.002) onControl(0, delta * 300, 'zoom');
      }
      prevHandDistanceRef.current = dist;
    } else if (!isPinchingRef.current) {
      prevHandDistanceRef.current = null;
      const x = screenX; 
      const y = screenY; 
      let dx = 0, dy = 0;
      const DEADZONE = 0.15;
      const CENTER = 0.5;
      if (Math.abs(x - CENTER) > DEADZONE) dx = (x - CENTER) * 2.0;
      if (y < CENTER - DEADZONE) dy = (y - CENTER) * 2.0;
      onControl(dx, dy, 'rotate');
    }
  };

  const draw = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (!isARMode && videoRef.current) {
        ctx.save();
        ctx.scale(-1, 1);
        ctx.drawImage(videoRef.current, -canvas.width, 0, canvas.width, canvas.height);
        ctx.restore();
        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        const connections = HandLandmarker.HAND_CONNECTIONS;
        ctx.strokeStyle = isPinchingRef.current ? "#ff0000" : "#00ffff";
        ctx.lineWidth = 3;
        for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          ctx.beginPath();
          ctx.moveTo((1 - start.x) * canvas.width, start.y * canvas.height);
          ctx.lineTo((1 - end.x) * canvas.width, end.y * canvas.height);
          ctx.stroke();
        }
        ctx.fillStyle = "#ff00ff";
        for (const lm of landmarks) {
           ctx.beginPath();
           ctx.arc((1 - lm.x) * canvas.width, lm.y * canvas.height, 4, 0, 2 * Math.PI);
           ctx.fill();
        }
        // 绘制准星
        const cursor = landmarks[9];
        ctx.strokeStyle = "white";
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc((1 - cursor.x) * canvas.width, cursor.y * canvas.height, 10, 0, Math.PI * 2);
        ctx.stroke();
      }
    }
  };

  return (
    <>
      <video ref={videoRef} className={`fixed inset-0 w-full h-full object-cover -scale-x-100 transition-opacity duration-300 ${isARMode ? 'z-[-10] opacity-100' : 'z-[-20] opacity-0 pointer-events-none'}`} autoPlay playsInline muted onLoadedData={predictWebcam} />
      {isARMode && <div className="fixed inset-0 w-full h-full bg-black/60 backdrop-blur-md z-[-9] pointer-events-none transition-all duration-500" />}
      <canvas ref={canvasRef} width={320} height={240} className={`fixed bottom-20 right-4 w-40 h-32 rounded-lg border-2 border-white/20 shadow-lg z-50 bg-black/50 pointer-events-none transition-opacity duration-300 ${isARMode ? 'opacity-0' : 'opacity-100'}`} />
      <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 pointer-events-auto animate-fade-in">
        <div className="bg-slate-900/80 backdrop-blur border border-cyan-500/30 text-cyan-300 px-4 py-2 rounded-full font-bold shadow-lg flex items-center gap-2">
           <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400' : 'bg-green-400'} animate-pulse`}></span>
           {statusMessage}
        </div>
        <div className="flex items-center gap-3">
           <button onClick={toggleARMode} disabled={loading || permissionError} className={`h-12 px-5 rounded-full font-bold text-sm shadow-lg border-2 transition-all flex items-center gap-2 ${isARMode ? 'bg-cyan-500 text-black border-cyan-200 shadow-[0_0_15px_#22d3ee]' : 'bg-slate-800 text-white border-slate-600 hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed'}`}>
             <span>{isARMode ? "📺 关闭画面" : "📹 显示画面 (AR)"}</span>
           </button>
           <button onClick={onClose} className="w-12 h-12 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white/20 active:scale-95 transition-all">✕</button>
        </div>
      </div>
    </>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping, MathUtils, Raycaster, Vector2 } from 'three';
import { PLANETS, SUN_DATA, JUPITER_MOONS, SATURN_MOONS, MOON_DATA, TIANGONG_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0001; 
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

const CameraFlyTo = ({ target, planetRefs, controlsRef, setTarget }: { target: { id: string, size: number } | null, planetRefs: any, controlsRef: any, setTarget: any }) => {
  useFrame((state, delta) => {
    if (!target) return;
    const { id, size } = target;
    const targetObj = planetRefs.current[id];

    if (!targetObj) {
      setTarget(null);
      return;
    }

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    const currentCamPos = state.camera.position.clone();
    const dir = new Vector3().subVectors(currentCamPos, targetPos).normalize();

    const zoomDist = id === 'sun' ? 140 : Math.max(size * 4, 6.0); 
    const desiredCamPos = targetPos.clone().add(dir.multiplyScalar(zoomDist));

    const lerpFactor = 4.0 * delta;

    controlsRef.current.target.lerp(targetPos, lerpFactor);
    state.camera.position.lerp(desiredCamPos, lerpFactor);
    controlsRef.current.update();

    if (state.camera.position.distanceTo(desiredCamPos) < 0.2 && 
        controlsRef.current.target.distanceTo(targetPos) < 0.1) {
       setTarget(null); 
    }
  });
  return null;
}

const GestureHandler = ({ action, setAction, handleDoubleClick, handleClose }: { action: any, setAction: any, handleDoubleClick: any, handleClose: any }) => {
  const { camera, scene } = useThree();
  const raycaster = useMemo(() => new Raycaster(), []);

  useEffect(() => {
    if (!action) return;

    if (action.type === 'peace') {
      handleClose();
      setAction(null);
    } else if (action.type === 'pinch') {
      // 射线检测：寻找手势所在的 3D 物体
      const mouse = new Vector2(action.x * 2 - 1, -(action.y * 2 - 1));
      raycaster.setFromCamera(mouse, camera);
      const intersects = raycaster.intersectObjects(scene.children, true);

      if (intersects.length > 0) {
        // 找到第一个具有 ID 的父级或自身
        let targetId: string | null = null;
        for (let intersect of intersects) {
          let obj: Object3D | null = intersect.object;
          while (obj) {
             // 检查是否属于我们注册的行星引用
             if (obj.userData?.id) { targetId = obj.userData.id; break; }
             // 兼容性逻辑：直接检查 name 或通过上下文映射
             obj = obj.parent;
          }
          if (targetId) break;
        }

        // 如果没通过 userData 找到，尝试直接通过交互物体的碰撞箱逻辑（在此场景下行星材质可能有特定 ID）
        // 这里我们做一个简化的回退检查：
        if (!targetId) {
           // 检查该物体是否在我们的引用池中
           const entry = Object.entries((scene as any).__planetRefs || {}).find(([id, ref]: [any, any]) => {
              return intersects.some(intersect => {
                 let curr: Object3D | null = intersect.object;
                 while(curr) { if (curr === ref) return true; curr = curr.parent; }
                 return false;
              });
           });
           if (entry) targetId = entry[0];
        }

        if (targetId) {
          handleDoubleClick(targetId);
        }
      }
      setAction(null);
    }
  }, [action, camera, scene, raycaster, handleDoubleClick, handleClose, setAction]);

  return null;
}

const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;
      const smoothFactor = 5.0 * delta;
      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;
      if (activeDx !== 0 || activeDy !== 0) {
          if (gestureType === 'rotate') {
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);
             if (activeDy < 0) controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);
          } else if (gestureType === 'zoom') {
             const speed = 1.0 + Math.abs(activeDy * 0.015);
             if (activeDy > 0) controlsRef.current.dollyOut(speed);
             else controlsRef.current.dollyIn(speed);
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);
  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); 
  const [focusTarget, setFocusTarget] = useState<{ id: string, size: number } | null>(null);
  const [pendingAction, setPendingAction] = useState<{ x: number, y: number, type: 'pinch' | 'peace' } | null>(null);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);
  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
    setFocusTarget({ id: SUN_DATA.id, size: SUN_DATA.size });
  };

  const getPlanetSize = (id: string): number => {
      if (id === 'sun') return SUN_DATA.size;
      if (id === 'moon') return MOON_DATA.size;
      if (id === 'tiangong') return TIANGONG_DATA.size;
      const p = PLANETS.find(x => x.id === id);
      if (p) return p.size;
      return 1; 
  };

  const handleDoubleClick = (id: string) => {
      const size = getPlanetSize(id);
      setFocusTarget({ id, size });
      handleSelect(id);
  };

  const handleGestureAction = (x: number, y: number, type: 'pinch' | 'peace') => {
    setPendingAction({ x, y, type });
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    return [...JUPITER_MOONS, ...SATURN_MOONS].find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  return (
    <div className="w-full h-screen relative overflow-hidden" style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}>
      <UIOverlay 
        selectedPlanet={selectedPlanet} onClose={handleClose} isPaused={isPaused} togglePause={() => setIsPaused(!isPaused)} simulationSpeed={simulationSpeed} setSimulationSpeed={setSimulationSpeed} isStarshipActive={isStarshipActive} toggleStarship={() => setIsStarshipActive(!isStarshipActive)} showPluto={showPluto} togglePluto={() => setShowPluto(!showPluto)} isGestureMode={isGestureMode} toggleGestureMode={() => setIsGestureMode(!isGestureMode)} showOrbits={showOrbits} toggleOrbits={() => setShowOrbits(!showOrbits)}
      />
      {isGestureMode && (
        <GestureController onControl={(dx, dy, gt) => { gestureVelocity.current = { dx, dy, gestureType: gt }; }} onAction={handleGestureAction} onClose={() => setIsGestureMode(false)} isARMode={isARMode} toggleARMode={() => setIsARMode(!isARMode)} />
      )}
      <Canvas gl={{ antialias: true, alpha: true }} onPointerMissed={() => selectedPlanetId && handleClose()} onCreated={(state) => { (state.scene as any).__planetRefs = planetRefs.current; }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />
          <OrbitControls ref={controlsRef} makeDefault enabled={!isStarshipActive} enableDamping dampingFactor={0.05} enablePan={false} minDistance={2} maxDistance={500} autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive && !focusTarget} autoRotateSpeed={0.1 * simulationSpeed} />
          <CameraFlyTo target={focusTarget} planetRefs={planetRefs} controlsRef={controlsRef} setTarget={setFocusTarget} />
          <GestureHandler action={pendingAction} setAction={setPendingAction} handleDoubleClick={handleDoubleClick} handleClose={handleClose} />
          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />
          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} />
          <ambientLight intensity={0.15} />
          <Stars radius={400} />
          {!isARMode && <Skybox />}
          <Sparkles count={400} scale={200} size={6} />
          <Sun onSelect={handleSelect} onDoubleClick={handleDoubleClick} isSelected={selectedPlanetId === 'sun'} isPaused={isPaused} simulationSpeed={simulationSpeed} planetRefs={planetRefs} />
          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />
          {(showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto')).map((planet) => (
            <Planet key={planet.id} data={planet} isSelected={selectedPlanetId === planet.id} onSelect={handleSelect} onDoubleClick={handleDoubleClick} isPaused={isPaused} simulationSpeed={simulationSpeed} earthPositionRef={earthPositionRef} planetRefs={planetRefs} isStarshipActive={isStarshipActive} showOrbit={showOrbits} />
          ))}
          {isStarshipActive && <Starship planetRefs={planetRefs} onMissionComplete={() => setIsStarshipActive(false)} />}
        </Suspense>
      </Canvas>
    </div>
  );
};
export default App;

import React, { useEffect, useRef, useState } from 'react';
import { FilesetResolver, HandLandmarker, HandLandmarkerResult } from '@mediapipe/tasks-vision';

interface GestureControllerProps {
  onControl: (dx: number, dy: number, gestureType: 'rotate' | 'zoom') => void;
  onAction: (x: number, y: number, actionType: 'pinch' | 'peace') => void;
  onClose: () => void;
  isARMode: boolean;
  toggleARMode: () => void;
}

export const GestureController: React.FC<GestureControllerProps> = ({ 
  onControl, 
  onAction,
  onClose,
  isARMode,
  toggleARMode
}) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [loading, setLoading] = useState(true);
  const [permissionError, setPermissionError] = useState(false);
  const landmarkerRef = useRef<HandLandmarker | null>(null);
  const requestRef = useRef<number>(0);

  const prevHandDistanceRef = useRef<number | null>(null);
  const lastActionTimeRef = useRef<number>(0);
  const isPinchingRef = useRef<boolean>(false);

  const [statusMessage, setStatusMessage] = useState<string>("启动魔法手势...");

  useEffect(() => {
    let isMounted = true;
    const init = async () => {
      try {
        const vision = await FilesetResolver.forVisionTasks(
          "https://cdn.jsdelivr.net/npm/@mediapipe/tasks-vision@0.10.8/wasm"
        );
        if (!isMounted) return;
        landmarkerRef.current = await HandLandmarker.createFromOptions(vision, {
          baseOptions: {
            modelAssetPath: `https://storage.googleapis.com/mediapipe-models/hand_landmarker/hand_landmarker/float16/1/hand_landmarker.task`,
            delegate: "GPU"
          },
          runningMode: "VIDEO",
          numHands: 2
        });
        if (isMounted) startWebcam();
      } catch (error) {
        console.error("Error initializing MediaPipe:", error);
        if (isMounted) {
          setLoading(false);
          setStatusMessage("初始化失败");
        }
      }
    };
    init();
    return () => {
      isMounted = false;
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      if (videoRef.current && videoRef.current.srcObject) {
        const tracks = (videoRef.current.srcObject as MediaStream).getTracks();
        tracks.forEach(t => t.stop());
      }
    };
  }, []);

  const startWebcam = async () => {
    if (!videoRef.current) return;
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ 
        video: { width: { ideal: 640 }, height: { ideal: 480 }, facingMode: "user" } 
      });
      if (videoRef.current) videoRef.current.srcObject = stream;
      setLoading(false);
      setStatusMessage("准备好了！");
    } catch (err) {
      console.error("Webcam error:", err);
      setPermissionError(true);
      setLoading(false);
      setStatusMessage("无法打开摄像头");
    }
  };

  const predictWebcam = () => {
    if (!landmarkerRef.current || !videoRef.current) return;
    if (videoRef.current.readyState < 2) {
        requestRef.current = requestAnimationFrame(predictWebcam);
        return;
    }
    const result = landmarkerRef.current.detectForVideo(videoRef.current, performance.now());
    processGestures(result);
    if (canvasRef.current) draw(result);
    requestRef.current = requestAnimationFrame(predictWebcam);
  };

  const processGestures = (result: HandLandmarkerResult) => {
    const hands = result.landmarks;
    if (!hands || hands.length === 0) {
      onControl(0, 0, 'rotate');
      prevHandDistanceRef.current = null;
      isPinchingRef.current = false;
      return;
    }

    const now = Date.now();
    const hand = hands[0];
    const cursor = hand[9]; // 掌心参考点
    const screenX = 1.0 - cursor.x;
    const screenY = cursor.y;

    // --- 1. 检测捏合 (大拇指和食指指尖靠近) ---
    const pinchDist = Math.hypot(hand[4].x - hand[8].x, hand[4].y - hand[8].y);
    const PINCH_THRESHOLD = 0.045;

    if (pinchDist < PINCH_THRESHOLD) {
      if (!isPinchingRef.current && (now - lastActionTimeRef.current > 800)) {
        isPinchingRef.current = true;
        lastActionTimeRef.current = now;
        onAction(screenX, screenY, 'pinch');
        setStatusMessage("👌 锁定目标！");
      }
    } else {
      isPinchingRef.current = false;
    }

    // --- 2. 检测比耶 (食指和中指伸出，其他合拢) ---
    const isIndexUp = hand[8].y < hand[6].y;
    const isMiddleUp = hand[12].y < hand[10].y;
    const isRingDown = hand[16].y > hand[14].y;
    const isPinkyDown = hand[20].y > hand[18].y;

    if (isIndexUp && isMiddleUp && isRingDown && isPinkyDown) {
      if (now - lastActionTimeRef.current > 1200) {
        lastActionTimeRef.current = now;
        onAction(screenX, screenY, 'peace');
        setStatusMessage("✌️ 魔法返回！");
      }
    }

    // --- 3. 基础缩放与旋转控制 ---
    if (hands.length === 2) {
      const h1 = hands[0][9]; 
      const h2 = hands[1][9];
      const dist = Math.hypot(h1.x - h2.x, h1.y - h2.y);
      if (prevHandDistanceRef.current !== null) {
        const delta = dist - prevHandDistanceRef.current;
        if (Math.abs(delta) > 0.002) onControl(0, delta * 300, 'zoom');
      }
      prevHandDistanceRef.current = dist;
    } else if (!isPinchingRef.current) {
      prevHandDistanceRef.current = null;
      const x = screenX; 
      const y = screenY; 
      let dx = 0, dy = 0;
      const DEADZONE = 0.15;
      const CENTER = 0.5;
      if (Math.abs(x - CENTER) > DEADZONE) dx = (x - CENTER) * 2.0;
      if (y < CENTER - DEADZONE) dy = (y - CENTER) * 2.0;
      onControl(dx, dy, 'rotate');
    }
  };

  const draw = (result: HandLandmarkerResult) => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    ctx.clearRect(0, 0, canvas.width, canvas.height);

    if (!isARMode && videoRef.current) {
        ctx.save();
        ctx.scale(-1, 1);
        ctx.drawImage(videoRef.current, -canvas.width, 0, canvas.width, canvas.height);
        ctx.restore();
        ctx.fillStyle = 'rgba(0, 0, 0, 0.3)';
        ctx.fillRect(0, 0, canvas.width, canvas.height);
    }

    if (result.landmarks) {
      for (const landmarks of result.landmarks) {
        const connections = HandLandmarker.HAND_CONNECTIONS;
        ctx.strokeStyle = isPinchingRef.current ? "#ff3e3e" : "#00ffff";
        ctx.lineWidth = 3;
        for (const conn of connections) {
          const start = landmarks[conn.start];
          const end = landmarks[conn.end];
          ctx.beginPath();
          ctx.moveTo((1 - start.x) * canvas.width, start.y * canvas.height);
          ctx.lineTo((1 - end.x) * canvas.width, end.y * canvas.height);
          ctx.stroke();
        }
        ctx.fillStyle = "#ff00ff";
        for (const lm of landmarks) {
           ctx.beginPath();
           ctx.arc((1 - lm.x) * canvas.width, lm.y * canvas.height, 4, 0, 2 * Math.PI);
           ctx.fill();
        }
        // 绘制聚焦准星
        const cursor = landmarks[9];
        ctx.strokeStyle = "white";
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.arc((1 - cursor.x) * canvas.width, cursor.y * canvas.height, 12, 0, Math.PI * 2);
        ctx.stroke();
        ctx.beginPath();
        ctx.moveTo((1 - cursor.x) * canvas.width - 18, cursor.y * canvas.height);
        ctx.lineTo((1 - cursor.x) * canvas.width + 18, cursor.y * canvas.height);
        ctx.moveTo((1 - cursor.x) * canvas.width, cursor.y * canvas.height - 18);
        ctx.lineTo((1 - cursor.x) * canvas.width, cursor.y * canvas.height + 18);
        ctx.stroke();
      }
    }
  };

  return (
    <>
      <video ref={videoRef} className={`fixed inset-0 w-full h-full object-cover -scale-x-100 transition-opacity duration-300 ${isARMode ? 'z-[-10] opacity-100' : 'z-[-20] opacity-0 pointer-events-none'}`} autoPlay playsInline muted onLoadedData={predictWebcam} />
      {isARMode && <div className="fixed inset-0 w-full h-full bg-black/60 backdrop-blur-md z-[-9] pointer-events-none transition-all duration-500" />}
      <canvas ref={canvasRef} width={320} height={240} className={`fixed bottom-20 right-4 w-40 h-32 rounded-lg border-2 border-white/20 shadow-lg z-50 bg-black/50 pointer-events-none transition-opacity duration-300 ${isARMode ? 'opacity-0' : 'opacity-100'}`} />
      <div className="absolute bottom-4 right-4 z-50 flex flex-col items-end gap-3 pointer-events-auto animate-fade-in">
        <div className="bg-slate-900/80 backdrop-blur border border-cyan-500/30 text-cyan-300 px-4 py-2 rounded-full font-bold shadow-lg flex items-center gap-2">
           <span className={`w-2 h-2 rounded-full ${loading ? 'bg-yellow-400' : 'bg-green-400'} animate-pulse`}></span>
           {statusMessage}
        </div>
        <div className="flex items-center gap-3">
           <button onClick={toggleARMode} disabled={loading || permissionError} className={`h-12 px-5 rounded-full font-bold text-sm shadow-lg border-2 transition-all flex items-center gap-2 ${isARMode ? 'bg-cyan-500 text-black border-cyan-200 shadow-[0_0_15px_#22d3ee]' : 'bg-slate-800 text-white border-slate-600 hover:bg-slate-700 disabled:opacity-50 disabled:cursor-not-allowed'}`}>
             <span>{isARMode ? "📺 关闭画面" : "📹 显示画面 (AR)"}</span>
           </button>
           <button onClick={onClose} className="w-12 h-12 bg-red-500 hover:bg-red-400 text-white rounded-full flex items-center justify-center shadow-lg border-2 border-white/20 active:scale-95 transition-all">✕</button>
        </div>
      </div>
    </>
  );
};

import React, { useState, Suspense, useRef, useMemo, useEffect } from 'react';
import { Canvas, useFrame, useThree } from '@react-three/fiber';
import { OrbitControls, Sparkles, PerspectiveCamera, Environment, Stars } from '@react-three/drei';
import { Vector3, TextureLoader, BackSide, Mesh, Object3D, RepeatWrapping, ClampToEdgeWrapping, MathUtils, Raycaster, Vector2 } from 'three';
import { PLANETS, SUN_DATA, JUPITER_MOONS, SATURN_MOONS, MOON_DATA, TIANGONG_DATA } from './constants';
import { Planet } from './components/Planet';
import { Sun } from './components/Sun';
import { Starship } from './components/Starship';
import { AsteroidBelt } from './components/AsteroidBelt';
import { UIOverlay } from './components/UIOverlay';
import { GestureController } from './components/GestureController';
import { generateStarFieldTexture } from './utils/textureGenerator';

const Skybox: React.FC = () => {
  const meshRef = useRef<Mesh>(null);
  const starTextureUrl = useMemo(() => generateStarFieldTexture(), []);
  const starTexture = useMemo(() => {
    const t = new TextureLoader().load(starTextureUrl);
    t.wrapS = RepeatWrapping;
    t.wrapT = ClampToEdgeWrapping; 
    return t;
  }, [starTextureUrl]);

  useFrame((state, delta) => {
    if (meshRef.current) {
      meshRef.current.rotation.y += delta * 0.0001; 
    }
  });

  return (
    <mesh ref={meshRef}>
      <sphereGeometry args={[500, 64, 64]} />
      <meshBasicMaterial 
        map={starTexture} 
        side={BackSide} 
        color="#ffffff"
      />
    </mesh>
  );
};

const CameraFlyTo = ({ target, planetRefs, controlsRef, setTarget }: { target: { id: string, size: number } | null, planetRefs: any, controlsRef: any, setTarget: any }) => {
  useFrame((state, delta) => {
    if (!target) return;
    const { id, size } = target;
    const targetObj = planetRefs.current[id];

    if (!targetObj) {
      setTarget(null);
      return;
    }

    const targetPos = new Vector3();
    targetObj.getWorldPosition(targetPos);

    const currentCamPos = state.camera.position.clone();
    const dir = new Vector3().subVectors(currentCamPos, targetPos).normalize();

    const zoomDist = id === 'sun' ? 140 : Math.max(size * 4, 6.0); 
    const desiredCamPos = targetPos.clone().add(dir.multiplyScalar(zoomDist));

    const lerpFactor = 4.0 * delta;

    controlsRef.current.target.lerp(targetPos, lerpFactor);
    state.camera.position.lerp(desiredCamPos, lerpFactor);
    controlsRef.current.update();

    if (state.camera.position.distanceTo(desiredCamPos) < 0.2 && 
        controlsRef.current.target.distanceTo(targetPos) < 0.1) {
       setTarget(null); 
    }
  });
  return null;
}

const GestureHandler = ({ action, setAction, onDoubleClick, onClose }: { action: any, setAction: any, onDoubleClick: any, onClose: any }) => {
  const { camera, scene } = useThree();
  const raycaster = useMemo(() => new Raycaster(), []);

  useEffect(() => {
    if (!action) return;

    if (action.type === 'peace') {
      onClose();
      setAction(null);
    } else if (action.type === 'pinch') {
      // 射线检测：寻找手势所在的 3D 物体
      // 手势坐标是 0 到 1，需要转换成 -1 到 1 的 NDC 坐标
      const mouse = new Vector2(action.x * 2 - 1, -(action.y * 2 - 1));
      raycaster.setFromCamera(mouse, camera);

      const intersects = raycaster.intersectObjects(scene.children, true);

      if (intersects.length > 0) {
        let targetId: string | null = null;
        // 查找击中物体或其父级是否在 planetRefs 中
        for (let intersect of intersects) {
           let obj: Object3D | null = intersect.object;
           while (obj) {
              if (obj.userData?.id) { targetId = obj.userData.id; break; }
              // 兼容性逻辑：通过 scene.__planetRefs 映射反向查找
              const planetRefs = (scene as any).__planetRefs || {};
              const foundId = Object.keys(planetRefs).find(id => planetRefs[id] === obj);
              if (foundId) { targetId = foundId; break; }
              obj = obj.parent;
           }
           if (targetId) break;
        }

        if (targetId) {
          onDoubleClick(targetId);
        }
      }
      setAction(null);
    }
  }, [action, camera, scene, raycaster, onDoubleClick, onClose, setAction]);

  return null;
}

const OrbitController = ({ controlsRef, gestureVelocity }: { controlsRef: any, gestureVelocity: React.MutableRefObject<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}> }) => {
  const smoothed = useRef({ dx: 0, dy: 0 });

  useFrame((state, delta) => {
    if (controlsRef.current && controlsRef.current.enabled) {
      const { dx, dy, gestureType } = gestureVelocity.current;
      const smoothFactor = 5.0 * delta;
      smoothed.current.dx = MathUtils.lerp(smoothed.current.dx, dx, smoothFactor);
      smoothed.current.dy = MathUtils.lerp(smoothed.current.dy, dy, smoothFactor);
      const threshold = 0.001; 
      const activeDx = Math.abs(smoothed.current.dx) > threshold ? smoothed.current.dx : 0;
      const activeDy = Math.abs(smoothed.current.dy) > threshold ? smoothed.current.dy : 0;
      if (activeDx !== 0 || activeDy !== 0) {
          if (gestureType === 'rotate') {
             controlsRef.current.setAzimuthalAngle(controlsRef.current.getAzimuthalAngle() - activeDx * 0.02);
             if (activeDy < 0) controlsRef.current.setPolarAngle(controlsRef.current.getPolarAngle() - activeDy * 0.02);
          } else if (gestureType === 'zoom') {
             const speed = 1.0 + Math.abs(activeDy * 0.015);
             if (activeDy > 0) controlsRef.current.dollyOut(speed);
             else controlsRef.current.dollyIn(speed);
          }
          controlsRef.current.update();
      }
    }
  });
  return null;
}

const App: React.FC = () => {
  const [selectedPlanetId, setSelectedPlanetId] = useState<string | null>(null);
  const [isPaused, setIsPaused] = useState(false);
  const [simulationSpeed, setSimulationSpeed] = useState(1.0); 
  const [isStarshipActive, setIsStarshipActive] = useState(false);
  const [showPluto, setShowPluto] = useState(false);
  const [showOrbits, setShowOrbits] = useState(true);
  const [isGestureMode, setIsGestureMode] = useState(false);
  const [isARMode, setIsARMode] = useState(false); 
  const [focusTarget, setFocusTarget] = useState<{ id: string, size: number } | null>(null);
  const [pendingAction, setPendingAction] = useState<{ x: number, y: number, type: 'pinch' | 'peace' } | null>(null);

  const earthPositionRef = useRef<Vector3>(new Vector3(0, 0, 0));
  const planetRefs = useRef<{ [key: string]: Object3D }>({});
  const controlsRef = useRef<any>(null);
  const gestureVelocity = useRef<{dx: number, dy: number, gestureType: 'rotate' | 'zoom'}>({ dx: 0, dy: 0, gestureType: 'rotate' });

  useEffect(() => {
    document.body.style.backgroundColor = isARMode ? 'transparent' : '#000';
  }, [isARMode]);

  const handleSelect = (id: string) => {
    setSelectedPlanetId(id);
    setIsPaused(true); 
  };

  const handleClose = () => {
    setSelectedPlanetId(null);
    setIsPaused(false); 
    setFocusTarget({ id: SUN_DATA.id, size: SUN_DATA.size });
  };

  const getPlanetSize = (id: string): number => {
      if (id === 'sun') return SUN_DATA.size;
      if (id === 'moon') return MOON_DATA.size;
      if (id === 'tiangong') return TIANGONG_DATA.size;
      const p = PLANETS.find(x => x.id === id);
      if (p) return p.size;
      return 1; 
  };

  const handleDoubleClick = (id: string) => {
      const size = getPlanetSize(id);
      setFocusTarget({ id, size });
      handleSelect(id);
  };

  const handleGestureAction = (x: number, y: number, actionType: 'pinch' | 'peace') => {
    setPendingAction({ x, y, type: actionType });
  };

  const selectedPlanet = useMemo(() => {
    if (selectedPlanetId === 'sun') return SUN_DATA;
    if (selectedPlanetId === 'moon') return MOON_DATA;
    if (selectedPlanetId === 'tiangong') return TIANGONG_DATA;
    const planet = PLANETS.find(p => p.id === selectedPlanetId);
    if (planet) return planet;
    return [...JUPITER_MOONS, ...SATURN_MOONS].find(m => m.id === selectedPlanetId) || null;
  }, [selectedPlanetId]);

  return (
    <div className="w-full h-screen relative overflow-hidden" style={{ backgroundColor: isARMode ? 'transparent' : '#000' }}>
      <UIOverlay 
        selectedPlanet={selectedPlanet} onClose={handleClose} isPaused={isPaused} togglePause={() => setIsPaused(!isPaused)} simulationSpeed={simulationSpeed} setSimulationSpeed={setSimulationSpeed} isStarshipActive={isStarshipActive} toggleStarship={() => setIsStarshipActive(!isStarshipActive)} showPluto={showPluto} togglePluto={() => setShowPluto(!showPluto)} isGestureMode={isGestureMode} toggleGestureMode={() => setIsGestureMode(!isGestureMode)} showOrbits={showOrbits} toggleOrbits={() => setShowOrbits(!showOrbits)}
      />
      {isGestureMode && (
        <GestureController onControl={(dx, dy, gt) => { gestureVelocity.current = { dx, dy, gestureType: gt }; }} onAction={handleGestureAction} onClose={() => setIsGestureMode(false)} isARMode={isARMode} toggleARMode={() => setIsARMode(!isARMode)} />
      )}
      <Canvas gl={{ antialias: true, alpha: true }} onPointerMissed={() => selectedPlanetId && handleClose()} onCreated={(state) => { (state.scene as any).__planetRefs = planetRefs.current; }}>
        <Suspense fallback={null}>
          <PerspectiveCamera makeDefault position={[0, 80, 120]} fov={45} />
          <OrbitControls ref={controlsRef} makeDefault enabled={!isStarshipActive} enableDamping dampingFactor={0.05} enablePan={false} minDistance={2} maxDistance={500} autoRotate={!selectedPlanetId && !isPaused && !isGestureMode && !isStarshipActive && !focusTarget} autoRotateSpeed={0.1 * simulationSpeed} />
          <CameraFlyTo target={focusTarget} planetRefs={planetRefs} controlsRef={controlsRef} setTarget={setFocusTarget} />
          <GestureHandler action={pendingAction} setAction={setPendingAction} onDoubleClick={handleDoubleClick} onClose={handleClose} />
          <OrbitController controlsRef={controlsRef} gestureVelocity={gestureVelocity} />
          <Environment preset="city" environmentIntensity={0.3} />
          <pointLight position={[0, 0, 0]} intensity={2.5} distance={500} />
          <ambientLight intensity={0.15} />
          <Stars radius={400} />
          {!isARMode && <Skybox />}
          <Sparkles count={400} scale={200} size={6} />
          <Sun onSelect={handleSelect} onDoubleClick={handleDoubleClick} isSelected={selectedPlanetId === 'sun'} isPaused={isPaused} simulationSpeed={simulationSpeed} planetRefs={planetRefs} />
          <AsteroidBelt isPaused={isPaused} simulationSpeed={simulationSpeed} />
          {(showPluto ? PLANETS : PLANETS.filter(p => p.id !== 'pluto')).map((planet) => (
            <Planet key={planet.id} data={planet} isSelected={selectedPlanetId === planet.id} onSelect={handleSelect} onDoubleClick={handleDoubleClick} isPaused={isPaused} simulationSpeed={simulationSpeed} earthPositionRef={earthPositionRef} planetRefs={planetRefs} isStarshipActive={isStarshipActive} showOrbit={showOrbits} />
          ))}
          {isStarshipActive && <Starship planetRefs={planetRefs} onMissionComplete={() => setIsStarshipActive(false)} />}
        </Suspense>
      </Canvas>
    </div>
  );
};
export default App;
